            const email = document.getElementById('email').value;

            if (!name || !email) {
                alert("Please fill in all required fields.");
                return false;
            }

            if (!validateEmail(email)) {
                document.getElementById('emailError').innerText = "Invalid email format.";
                return false;
            }

            document.getElementById('emailError').innerText = "";
            return true;
        }

        function validateEmail(email) {
            const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            return re.test(String(email).toLowerCase());
        }
    </script>
</head>
<body>
    <h1>Simple User Input Form</h1>
    <form id="userForm" method="post" action="/submit-form" onsubmit="return validateForm()">
        <div>
            <label for="name">Name:</label>
            <input type="text" id="name" name="name" required>
            <span id="nameError" class="error"></span>
        </div>
        <div>
            <label for="email">Email:</label>
            <input type="email" id="email" name="email" required>
            <span id="emailError" class="error"></span>
        </div>
        <button type="submit">Submit</button>
    </form>
</body>
</html>
```

#### 2. Server-Side Validation and Saving Data
Next, let's set up a simple server-side script to handle the form submission. We'll use Node.js with Express for this example.

First, install the necessary packages:

```sh
npm init -y
npm install express body-parser
```

Then, create a file named `server.js`:

```javascript
const express = require('express');
const bodyParser = require('body-parser');
const app = express();
const port = 3000;

// Middleware to parse JSON bodies
app.use(bodyParser.json());

// Route to handle form submission
app.post('/submit-form', (req, res) => {
    const { name, email } = req.body;

    // Basic validation on the server side
    if (!name || !email) {
        return res.status(400).json({ error: "All fields are required." });
    }

    if (!validateEmail(email)) {
        return res.status(400).json({ error: "Invalid email format." });
    }

    // Save the data to a simple in-memory array (for demonstration purposes)
    const users = JSON.parse(process.env.USERS_DATA || '[]');
    users.push({ name, email });

    // Save the updated list of users
    process.env.USERS_DATA = JSON.stringify(users);

    res.status(200).json({ message: "Form submitted successfully!" });
});

// Function to validate email
function validateEmail(email) {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(String(email).toLowerCase());
}

// Start the server
app.listen(port, () => {
    console.log(`Server running on http://localhost:${port}`);
});
```

#### 3. Environment Variable Setup
Create a `.env` file to store the in-memory data:

```
USERS_DATA='[{"name": "John Doe", "email": "john@example.com"}, {"name": "Jane Smith", "email": "jane@example.com"}]'
```

#### 4. Running the Application
To run the application, navigate to the project directory and start the server:

```sh
node server.js
```

Now, when you open the HTML form in your browser and submit it, the client-side validation will check the fields, and the server-side validation will ensure the data is valid before saving it.

### Summary

- **HTML Form**: Contains client-side validation to ensure fields are filled correctly.
- **Server-Side Script**: Handles form submissions, performs server-side validation, and saves the data.
- **Environment Variable**: Stores in-memory data for demonstration purposes.

This setup ensures that your form is both user-friendly and secure, helping you meet your project's requirements effectively.

Certainly! A practical example will help your students understand the entire process of creating a form, capturing user input, and saving it to a database. Let's walk through a simple example using HTML, JavaScript, and a basic backend with Node.js and Express.

### Step 1: Setting Up the Frontend

First, we'll create a simple HTML form that captures user input.

#### `index.html`
```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Simple Form Example</title>
</head>
<body>
    <h1>Simple Form Example</h1>
    <form id="userForm">
        <label for="name">Name:</label>
        <input type="text" id="name" name="name" required><br><br>

        <label for="email">Email:</label>
        <input type="email" id="email" name="email" required><br><br>

        <button type="submit">Submit</button>
    </form>

    <script src="app.js"></script>
</body>
</html>
```

### Step 2: Handling Form Submission with JavaScript

Next, we'll add JavaScript to handle the form submission and send the data to the server.

#### `app.js`
```javascript
document.getElementById('userForm').addEventListener('submit', function(event) {
    event.preventDefault(); // Prevent the default form submission

    const name = document.getElementById('name').value;
    const email = document.getElementById('email').value;

    fetch('/submit', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({ name, email })
    })
    .then(response => response.json())
    .then(data => {
        alert('Form submitted successfully!');
        console.log(data);
    })
    .catch(error => {
        console.error('Error:', error);
    });
});
```

### Step 3: Setting Up the Backend with Node.js and Express

Now, let's set up a simple backend using Node.js and Express to handle the form submission and save the data to a file (for simplicity). In a real-world scenario, you would typically use a database like MongoDB or PostgreSQL.

#### `server.js`
```javascript
const express = require('express');
const bodyParser = require('body-parser');
const fs = require('fs');

const app = express();
const PORT = 3000;

// Middleware to parse JSON bodies
app.use(bodyParser.json());

// Endpoint to handle form submissions
app.post('/submit', (req, res) => {
    const { name, email } = req.body;

    // Save the data to a file (for simplicity)
    const data = `${name}, ${email}\n`;
    fs.appendFile('users.txt', data, (err) => {
        if (err) {
            return res.status(500).send('Error saving data.');
        }
        res.send('Data saved successfully!');
    });
});

// Serve the frontend files
app.use(express.static('public'));

app.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
});
```

### Step 4: Directory Structure

Ensure your project directory structure looks like this:

```
project-root/
│
├── public/
│   ├── index.html
│   └── app.js
│
└── server.js
```

### Step 5: Running the Application

1. **Install Dependencies:**
   ```sh
   npm init -y
   npm install express body-parser
   ```

2. **Run the Server:**
   ```sh
   node server.js
   ```

3. **Open the Form:**
   Open your browser and navigate to `http://localhost:3000`. You should see the form, and when you submit it, the data will be saved to `users.txt` in the same directory.

### Summary

This example covers the entire process from creating a simple form, handling form submission with JavaScript, and sending the data to a server using a basic Express backend. The data is then saved to a file for demonstration purposes. This hands-on exercise will help your students understand the practical aspects of form handling in web development.

